def fix_guid(val):
    if re.match(r'^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$', val.strip()):
        return val.strip()
    return NULL_GUID

def fix_date(val):
    # Strip time portion if present e.g. "2013-07-19 00:00:00" -> "2013-07-19"
    val = val.strip()
    try:
        return datetime.strptime(val, "%Y-%m-%d %H:%M:%S").strftime("%Y-%m-%d")
    except ValueError:
        pass
    try:
        return datetime.strptime(val, "%Y-%m-%d").strftime("%Y-%m-%d")
    except ValueError:
        pass
    try:
        return datetime.strptime(val, "%d/%m/%Y").strftime("%Y-%m-%d")
    except ValueError:
        return val  # leave as-is if unrecognised
